const rows = $input.all();
  const TOKEN = '<LINE_CHANNEL_ACCESS_TOKEN>';
  const GROUP_ID = '<LINE_GROUP_ID>';

  const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Taipei' }));
  const pad = n => String(n).padStart(2, '0');
  const fmt = d => d.getFullYear() + '/' + pad(d.getMonth() + 1) + '/' + pad(d.getDate());
  const wd = ['週日','週一','週二','週三','週四','週五','週六'];

  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const sunday = new Date(today); sunday.setDate(today.getDate() + ((7 - today.getDay()) % 7)); // 本週日

  const todayStr = fmt(today);
  const weekStartStr = todayStr;
  const weekEndStr = fmt(sunday);

  function getRange(d) {
    d = String(d || '').trim(); if (!d) return null;
    if (d.includes('~')) { const a = d.split('~'); return [a[0].trim(), a[1].trim()]; }
    return [d, d];
  }
  function hitsDay(d, dayStr) { const r = getRange(d); return r ? (r[0] <= dayStr && dayStr <= r[1]) : false; }
  function hitsRange(d, s, e) { const r = getRange(d); return r ? (r[0] <= e && r[1] >= s) : false; }

  const active = rows.filter(r => String(r.json['狀態'] || '').trim() !== 'cancelled');
  const todayLeaves = active.filter(r => hitsDay(r.json['請假日期'], todayStr));
  const weekLeaves  = active.filter(r => hitsRange(r.json['請假日期'], weekStartStr, weekEndStr));

  function line(r) {
    const name = r.json['申請人'] || '?';
    const cat = r.json['假別'] || r.json['請假原因'] || '';
    const date = r.json['請假日期'] || '';
    const status = String(r.json['狀態'] || '').trim();
    const tag = status === 'confirmed' ? '✅' : '⏳';

    // 外出：顯示事由，不顯示時數
    if (cat === '外出') {
      const reason = r.json['請假原因'] || '外出';
      return `・${name}（${date}｜外出：${reason}）`;
    }

    // 請假：顯示時數（整天倍數→X天，否則→X小時）
    const h = Number(r.json['請假時數']);
    let hStr = '';
    if (!isNaN(h) && h > 0) hStr = (h % 8 === 0) ? `｜${h / 8}天` : `｜${h}小時`;
    return `・${name}（${date}｜${cat}${hStr}｜${tag}）`;
  }

  let msg = `🌅 歐嗨呦！津日 梅池道 早報 📋\n今天 ${todayStr}（${wd[today.getDay()]}）\n\n`;
  msg += `【今天請假】\n`;
  msg += todayLeaves.length ? todayLeaves.map(line).join('\n') : '今天全員出席 ✨';
  msg += `\n\n【本週 ${weekStartStr}~${weekEndStr}】\n`;
  msg += weekLeaves.length ? weekLeaves.map(line).join('\n') : '這段時間沒有人請假 ✨';

  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.line.me/v2/bot/message/push',
    headers: { 'Authorization': `Bearer ${TOKEN}`, 'Content-Type': 'application/json' },
    body: { to: GROUP_ID, messages: [{ type: 'text', text: msg }] }
  });
  return [{ json: { sent: true, msg } }];

const event = $json.body.events[0];
  const source = event.source;
  const to = source.type === 'group' ? source.groupId : source.userId;
  const userMessage = event.message.text;
  const quotedMessageId = event.message.quotedMessageId || null;

  const now = new Date(new Date().toLocaleString('en-US', {timeZone: 'Asia/Taipei'}));
  const pad = n => String(n).padStart(2, '0');
  const today = now.getFullYear()+'/'+pad(now.getMonth()+1)+'/'+pad(now.getDate());
  const weekdays = ['週日','週一','週二','週三','週四','週五','週六'];
  const nowStr = today+' '+pad(now.getHours())+':'+pad(now.getMinutes());

  const holidays = ['01/01','02/28','04/04','05/01','10/10',
    '02/16','02/17','02/18','02/19','02/20','02/21','04/05','06/19','09/25'];

  const fmt = d => d.getFullYear()+'/'+pad(d.getMonth()+1)+'/'+pad(d.getDate());

  function isOffDay(d) {
    if (d.getDay()===0||d.getDay()===6) return true;
    return holidays.includes(pad(d.getMonth()+1)+'/'+pad(d.getDate()));
  }

  function calcWorkdayRange(start, n) {                                                                                                                                                      
    let d = new Date(start);
    while (isOffDay(d)) d.setDate(d.getDate()+1);
    const s = new Date(d);
    let count = 1;
    while (count < n) { d.setDate(d.getDate()+1); if (!isOffDay(d)) count++; }
    return [s, d];
  }

  let upcomingHolidays = [];
  for (let i=0;i<=30;i++) {
    const d = new Date(now); d.setDate(now.getDate()+i);
    if (isOffDay(d)) upcomingHolidays.push(`${fmt(d)}(${weekdays[d.getDay()]})`);
  }

  let dateHint = '';
  const nDayMatch = userMessage.match(/(\d+)\s*天/);                                                                                                                                         
  if (nDayMatch) {
    const n = parseInt(nDayMatch[1]);
    let start;
    const dm = userMessage.match(/(\d{1,2})\/(\d{1,2})/)||userMessage.match(/(\d{1,2})月(\d{1,2})日/);
    if (dm) {
      start = new Date(now.getFullYear(), parseInt(dm[1])-1, parseInt(dm[2]));
      const diffDays = (now - start) / (1000*60*60*24);
      if (diffDays > 60) start.setFullYear(now.getFullYear()+1);
    } else if (userMessage.includes('明天')) { start=new Date(now); start.setDate(now.getDate()+1); }
    else if (userMessage.includes('後天')) { start=new Date(now); start.setDate(now.getDate()+2); }
    else if (userMessage.includes('下週一')||userMessage.includes('下周一')) {
      start=new Date(now); start.setDate(now.getDate()+((8-now.getDay())%7||7));
    } else { start=new Date(now); start.setDate(now.getDate()+1); }
    const [s,e] = calcWorkdayRange(start, n);
    const hours = n * 8;
    dateHint = `\n💡【系統已預先計算】${n}天工作天結果：${n===1?fmt(s):fmt(s)+'~'+fmt(e)}，時數=${hours}小時，請直接使用。`;
  }

  const replyHint = quotedMessageId
    ? '\n⚠️ 【這則訊息是用 LINE 的回覆功能發送的，表示在修改或補充前一則請假的內容，請對照 Sheet 中最近一筆相符的紀錄進行修改，不要新增。】'
    : '';

  const inputText = `今天:${today}(${weekdays[now.getDay()]})
  登記時間:${nowStr}
  未來30天假日:${upcomingHolidays.join(', ')}
  LINE 回覆對象:${to}${dateHint}${replyHint}

  LINE 訊息:${userMessage}`;

  return [{ json: { chatInput: inputText, inputText, to, nowStr } }];

const event = $('LINE Webhook').first().json.body.events[0];
  const source = event.source;
  const to = source.type === 'group' ? source.groupId : source.userId;
  const senderId = source.userId;
  const ALLOWED_GROUP_OCR = '<LINE_GROUP_ID>';
  if ((source.type === 'group' || source.type === 'room') && (source.groupId || source.roomId) !== ALLOWED_GROUP_OCR) return [];

  const binaryKey = Object.keys($input.first().binary || {})[0];
  if (!binaryKey) return [];
  const binaryData = $input.first().binary[binaryKey];
  const _buf = await this.helpers.getBinaryDataBuffer(0, binaryKey);
  const base64Image = Buffer.isBuffer(_buf) ? _buf.toString('base64') : (binaryData.data || '');
  const mimeType = binaryData.mimeType || 'image/jpeg';

  const now = new Date(new Date().toLocaleString('en-US', {timeZone: 'Asia/Taipei'}));
  const pad = n => String(n).padStart(2, '0');
  const nowStr = now.getFullYear()+'/'+pad(now.getMonth()+1)+'/'+pad(now.getDate())+
                 ' '+pad(now.getHours())+':'+pad(now.getMinutes());

  const holidays2026 = [
    '2026/01/01','2026/02/28','2026/04/04','2026/05/01','2026/10/10',
    '2026/02/16','2026/02/17','2026/02/18','2026/02/19','2026/02/20','2026/02/21',
    '2026/04/05','2026/06/19','2026/09/25'
  ];
  function isOffDay(d) {
    if (d.getDay()===0||d.getDay()===6) return true;
    const key = d.getFullYear()+'/'+pad(d.getMonth()+1)+'/'+pad(d.getDate());
    return holidays2026.includes(key);
  }
  function fmt(d) { return d.getFullYear()+'/'+pad(d.getMonth()+1)+'/'+pad(d.getDate()); }

  function calcWorkHours(startStr, endStr) {
    if (!startStr || !endStr) return null;
    const workStart = { h: 8, m: 45 }, workEnd = { h: 17, m: 45 };
    const lunchStart = { h: 12, m: 0 }, lunchEnd = { h: 13, m: 0 };
    const toMins = (h, m) => h * 60 + m;
    function dayWorkMins(dayS, dayE) {
      const ws = toMins(workStart.h, workStart.m), we = toMins(workEnd.h, workEnd.m);
      const ls = toMins(lunchStart.h, lunchStart.m), le = toMins(lunchEnd.h, lunchEnd.m);
      const s = Math.max(dayS, ws), e = Math.min(dayE, we);
      if (s >= e) return 0;
      let mins = e - s;
      const lOverlap = Math.max(0, Math.min(e, le) - Math.max(s, ls));
      mins -= lOverlap;
      return Math.max(0, mins);
    }
    const parseDateTime = str => {
      const parts = str.trim().split(' ');
      const [y, mo, d] = parts[0].split('/').map(Number);
      const [hh, mm] = (parts[1] || '08:45').split(':').map(Number);
      return new Date(y, mo - 1, d, hh, mm);
    };
    const start = parseDateTime(startStr), end = parseDateTime(endStr);
    let totalMins = 0, cur = new Date(start);
    while (cur <= end) {
      if (!isOffDay(cur)) {
        const isStartDay = cur.toDateString() === start.toDateString();
        const isEndDay = cur.toDateString() === end.toDateString();
        const dayS = isStartDay ? toMins(start.getHours(), start.getMinutes()) : toMins(workStart.h, workStart.m);
        const dayE = isEndDay ? toMins(end.getHours(), end.getMinutes()) : toMins(workEnd.h, workEnd.m);
        totalMins += dayWorkMins(dayS, dayE);
      }
      cur.setDate(cur.getDate() + 1); cur.setHours(0,0,0,0);
    }
    return Math.round(totalMins / 60 * 2) / 2;
  }
  function normDT(s) {
    if (!s) return s;
    s = String(s).replace(/[-\.]/g, '/').trim();
    return s.replace(/(\d{4}\/\d{1,2}\/\d{1,2})\s+(\d{2})(\d{2})\b/, '$1 $2:$3');
  }

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://127.0.0.1:8000/v1/chat/completions',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer <LOCAL_CHAT_API_KEY>' },
    body: {
      model: 'gemma-4-26b-a4b-it-4bit',
      messages: [{
        role: 'user',
        content: [
          { type: 'image_url', image_url: { url: `data:${mimeType};base64,${base64Image}` } },
          { type: 'text', text: `這是公司員工請假單截圖，可能有「一筆或多筆」請假紀錄（清單）。請抓出「每一筆」，只回覆以下 JSON，不要任何其他文字：
  {"is_leave_form": true 或 false, "appearance":"從〔表單截圖/紙本表單/純文字/照片/其他〕擇一", "reason":"若 false 就說明原因", "records":[{"name":"請假人姓名","start":"開始日期時間","end":"結束日期時間","type":"假別","days":"扣假天數的數字(沒有就0)","hours":"扣假時數的數字(沒有就0)","reason":"原因"}]}

  【先判斷圖片「外觀」appearance，再判 is_leave_form — 嚴格，有疑慮一律 false】
  appearance 是看「這張圖長什麼樣子」，擇一：
    · 表單截圖 = 公司請假/HR 系統的畫面（有欄位框、按鈕、系統標題列、表格框線）
    · 紙本表單 = 拍紙本制式請假單（有表格框線、欄位標籤、簽核欄、公司抬頭/印章）
    · 純文字 = 整張只是白底黑字、幾行打出來的字（就算把姓名/日期/假別/代理人列得很整齊，也是純文字）
    · 照片 = 風景、人物、桌布等與單據無關的圖
    · 其他 = 以上都不是
  is_leave_form 規則：
    · 只有 appearance 是「表單截圖」或「紙本表單」、且看起來是真的正式單據 → true
    · appearance 是「純文字 / 照片 / 其他」 → 一律 false
    · 圖中出現「假的/假裝/偽裝/測試/騙/fake/test」字眼 → 一律 false
  ⚠️ 判斷依據是「外觀像不像正式單據」，不是「有沒有寫到請假資訊」。把資料打成幾行字＝純文字＝false。寧可錯殺。

  【每一筆都要列出 — 重要】
  - 截圖有幾筆請假就輸出幾個 record，不要合併、不要漏。
  - 一筆 = 一個假別 + 一段期間。不同假別或不同日期 = 不同筆。
  - 只有一筆時，records 裡也是放一個。

  【name（每筆都要）】
  - ⛔「代理人」欄是代班的人，絕不可當 name。
  - ✅ 用「申請人」欄；若無用「代簽辦人」欄；忽略代理人欄。

  【start / end（每筆各自的開始、結束）】
  - 一律輸出 YYYY/MM/DD HH:mm（例：2026/06/05 16:45）。
  - 日期與時間分欄要合併；時間 hhmm 四碼轉 HH:mm（1645→16:45）。
  - 該筆若期間是 a~b，start 用 a、end 用 b。

  【type】取假別名稱去掉編號（00003-事假→事假；00204-生理假→生理假）。看不到填「其他」。
  【days / hours｜最重要，要逐字看清楚】期間描述裡幾乎都有「共X天Y時」或「共X天Y小時」(例「共1天0小時」代表 1 天 0 時) → days 填 X、hours 填 Y。這是最準的欄位，優先用它。沒有「共…」才退而求其次看「扣假天數」「扣假時數」欄。一律填數字、沒有就 0。⚠️「1天」是整天(系統自己算成8小時)，別跟「0小時」搞混。⚠️⚠️ 結束時間如「1745 / 17:45」的「17」是『時間』不是『時數』！時數只能取「共X天Y時」裡 Y 的值(共1天0小時→hours=0)，絕對不要把下班時間 17、18 之類當成 hours。
  【reason】取事由欄；無填 null。

  只回覆 JSON。` }
        ]
      }],
      temperature: 0.1
    },
    json: true
  });

  const content = ((response.choices && response.choices[0] && response.choices[0].message && response.choices[0].message.content) || '').trim();
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (!jsonMatch) return [];
  const parsed = JSON.parse(jsonMatch[0]);
  const _badLook = ['純文字','照片','其他'].includes(String(parsed.appearance||''));
  const isLeaveForm = (parsed.is_leave_form === true) && !_badLook;
  const formReason = parsed.reason || (parsed.appearance ? ('看起來是「' + parsed.appearance + '」') : '');
  let records = Array.isArray(parsed.records) ? parsed.records : (parsed.name ? [parsed] : []);

  const nameFix = { '楊滔鈞':'楊淄鈞', '楊洶鈞':'楊淄鈞' };

  const out = records.map(rec => {
    let name = rec.name || '';
    if (name && nameFix[name]) name = nameFix[name];
    const start = normDT(rec.start);
    const end = normDT(rec.end);
    const _sd = Number(rec.days); const _sh = Number(rec.hours);
    const _days = (!isNaN(_sd) && _sd > 0) ? _sd : 0;
    const _extraH = (!isNaN(_sh) && _sh > 0 && _sh <= 8) ? _sh : 0;   // 零頭時數不可能>8(滿8就是一天)，>8 必是把結束時間17:45的17當成時數 → 丟棄
    let date = null, hrs = null;
    const _sp = start ? start.split(' ')[0].split('/').map(Number) : null;
    if (_days >= 1 && _sp) {
      // 以「共X天」為權威：從開始日起算工作日；X天+Y零頭 → 跨 X(+Y>0再+1) 個工作日；時數 = X*8 + Y。不信任會看錯的結束日
      const _span = _days + (_extraH > 0 ? 1 : 0);
      let d = new Date(_sp[0], _sp[1]-1, _sp[2]);
      while (isOffDay(d)) d.setDate(d.getDate()+1);
      const s0 = new Date(d); let c = 1; while (c < _span) { d.setDate(d.getDate()+1); if (!isOffDay(d)) c++; }
      date = (_span === 1) ? fmt(s0) : fmt(s0)+'~'+fmt(d);
      hrs = _days * 8 + _extraH;
    } else if (_extraH > 0 && start) {
      // 只有時數(半天)→ 單日
      date = start.split(' ')[0];
      hrs = _extraH;
    } else {
      // 天數時數都讀不到 → 退回用上下班時間推算
      hrs = calcWorkHours(start, end);
      if (start && end) { const sd = start.split(' ')[0], ed = end.split(' ')[0]; date = (sd === ed) ? sd : sd+'~'+ed; }
    }
    return { name, start, end, type: rec.type || '其他', reason: rec.reason || (rec.type || '其他'),
             hours: (hrs !== null) ? hrs : null, date };
  }).filter(r => r.name || r.date);

  return [{ json: { records: out, to, nowStr, senderId, sourceType: source.type, isLeaveForm, formReason } }];

const values = $input.first().json.values || [];
  const rows = [];
  for (let i = 1; i < values.length; i++) {
    const r = values[i];
    if (!r[0]) continue;
    rows.push({
      row: i + 1,
      applicant: r[0] || '',
      date: r[1] || '',
      reason: r[2] || '',
      hours: r[3] || '',
      status: r[4] || '',
      category: r[5] || '',
      logtime: r[6] || '',
      lineid: r[7] || '',
      slip: r[8] || ''
    });
  } 

  const prev = $('處理輸入').first().json;
  const sheetJson = JSON.stringify(rows);
  const chatInput = prev.chatInput + '\n\n【請假紀錄 JSON（含正確 row 號，直接使用）】\n' + sheetJson;

  return [{ json: { chatInput, to: prev.to, nowStr: prev.nowStr } }];

const oc = $('OCR 解析').first().json;
  const records = oc.records || [];
  const to = oc.to;
  const nowStr = oc.nowStr;

  const leaveVals = ($('讀取 Sheet').first().json.values) || [];
  const empVals   = ($('讀取員工2').first().json.values) || [];
  if (oc.sourceType === 'user' && !empVals.some((r,i)=>i>0 && r[2] && r[2]===oc.senderId)) return [];
  // 假單防偽：OCR 判定不是正式請假單 → 回嗆、不寫入
  if (oc.isLeaveForm === false) {
    const why = oc.formReason ? ('（' + oc.formReason + '）') : '';
    const RTOKEN = '<LINE_CHANNEL_ACCESS_TOKEN>';
    try {
      await this.helpers.httpRequest({ method: 'POST', url: 'https://api.line.me/v2/bot/message/push',
        headers: { 'Authorization': `Bearer ${RTOKEN}`, 'Content-Type': 'application/json' },
        body: { to, messages: [{ type: 'text', text: '🤨 這張看起來不是正式的假單喔' + why + '\n別想用假的／測試圖騙我啦～請拍「公司正式請假單」再傳一次 😆' }] } });
    } catch (e) {}
    return [];
  }

  const leaves = [];
  for (let i = 1; i < leaveVals.length; i++) {
    const r = leaveVals[i]; if (!r[0]) continue;
    leaves.push({ row: i + 1, applicant: r[0]||'', date: r[1]||'', reason: r[2]||'', hours: r[3]||'',
      status: r[4]||'', category: r[5]||'', logtime: r[6]||'', lineid: r[7]||'', slip: r[8]||'' });
  }
  const emps = [];
  for (let i = 1; i < empVals.length; i++) { const r = empVals[i]; if (!r[0]) continue; emps.push({ real: r[0], nick: r[1]||'' }); }

  const parseD = s => { const p = String(s).split(' ')[0].trim().split('/').map(Number); return new Date(p[0], p[1]-1, p[2]); };
  function range(d) { if (!d) return null; if (String(d).includes('~')) { const a = d.split('~'); return [parseD(a[0]), parseD(a[1])]; } const x = parseD(d); return [x, x]; }
  function overlap(a, b) { return a[0] <= b[1] && a[1] >= b[0]; }
  function lev(a, b) {
    a = String(a); b = String(b);
    const m = a.length, n = b.length;
    const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
    for (let i = 0; i <= m; i++) dp[i][0] = i;
    for (let j = 0; j <= n; j++) dp[0][j] = j;
    for (let i = 1; i <= m; i++) for (let j = 1; j <= n; j++)
      dp[i][j] = Math.min(dp[i-1][j]+1, dp[i][j-1]+1, dp[i-1][j-1] + (a[i-1]===b[j-1]?0:1));
    return dp[m][n];
  }
  function findNick(raw) {
    if (!raw) return null;
    const low = s => String(s).toLowerCase();
    const rawL = low(raw);
    for (const e of emps) if (rawL === low(e.real) || rawL === low(e.nick)) return e.nick || e.real;
    for (const e of emps) {
      if (e.nick && (rawL.includes(low(e.nick)) || low(e.nick).includes(rawL))) return e.nick;
