// ===== 私訊：交接錄入（靠模板標記，upsert）=====
if (sourceType === 'user' &&
    (/交接單/.test(userMessage) || (/姓名[:：]/.test(userMessage) && /請假期間[:：]/.test(userMessage)))) {
  const nameM = userMessage.match(/姓名[:：]\s*(\S+)/);
  const dateM = userMessage.match(/請假期間[:：]\s*([0-9\/~]+)/);
  const agentM = userMessage.match(/代理人[:：][ \t]*(\S+)/);
  const hName = nameM ? nameM[1] : '';
  const hDate = dateM ? dateM[1] : '';
  const agentRaw = agentM ? agentM[1] : '';
  const agentNick = agentRaw ? (findNick(agentRaw) || agentRaw) : '';
  let existRow = null;
  for (let i = 1; i < handVals.length; i++) {
    const r = handVals[i];
    if (r[0] === hName && r[1] === hDate) { existRow = i + 1; break; }
  }
  if (existRow) {
    const oldRow = handVals[existRow - 1] || [];
    const oldContent = oldRow[2] || '';
    const oldAgent = oldRow[4] || '';
    const delim = '\n──── 更新 ' + nowStr + ' ────\n';
    const merged = oldContent
      ? (oldContent + delim + stripHandoverHeader(userMessage))
      : userMessage;
    const finalAgent = agentNick || oldAgent;
    return [{ json: { action: 'handover_update', to, row: existRow,
      hRow: [hName, hDate, merged, nowStr, finalAgent], agentNick: finalAgent, forwardContent: stripHandoverHeader(userMessage), applicant: hName, period: hDate,
      message: '更新好囉～ ' + hName + ' ' + hDate + ' 的交接我幫你接在原本的下面了（保留前面紀錄）📋✨', rows: [] } }];
  }
  return [{ json: { action: 'handover_add', to,
    hRow: [hName, hDate, userMessage, nowStr, agentNick], agentNick, forwardContent: stripHandoverHeader(userMessage), applicant: hName, period: hDate,
    message: '收到囉～ ' + hName + ' ' + hDate + ' 的交接我幫你存好了 📋\n代理的同事有需要就查得到，安心放假吧 😊', rows: [] } }];
}

// ===== 私訊：查交接 =====
if (sourceType === 'user') {
  const umL = userMessage.toLowerCase();
  let targetNick = null;
  for (const e of emps) {
    const nk = (e.nick || '').toLowerCase(), rl = (e.real || '').toLowerCase();
    if ((nk && umL.includes(nk)) || (rl && umL.includes(rl))) { targetNick = e.nick || e.real; break; }
  }
  // ===== 反查：targetNick 現在是誰的代理人 =====
  const reverseIntent = targetNick && /代理(?!人)[^，。]*?(誰|什麼|哪些|的(工作|事|事情|交接))/.test(userMessage);
  if (reverseIntent) {
    let covering = [];
    for (let i = 1; i < handVals.length; i++) {
      const r = handVals[i]; if (!r[0]) continue;
      if ((r[4] || '') === targetNick) covering.push({ name: r[0], date: r[1] });
    }
    if (!covering.length) {
      return [{ json: { action: 'reply', to, message: targetNick + ' 目前沒有被指定代理任何人耶 😊', rows: [] } }];
    }
    const list = covering.map(c => '・' + c.name + '（' + c.date + '）').join('\n');
    return [{ json: { action: 'reply', to, message: '📋 ' + targetNick + ' 目前是以下同事的代理人：\n' + list + '\n\n可以打「(姓名) 的交接」查看詳細內容哦～', rows: [] } }];
  }

  // ===== 正向：查某人的代理人是誰（只回代理人，不倒整張交接）=====
  const fwdProxyIntent = targetNick && /代理人/.test(userMessage) && /(誰|哪位)/.test(userMessage);
  if (fwdProxyIntent) {
    let pRecs = [];
    for (let i = 1; i < handVals.length; i++) { const r = handVals[i]; if (!r[0]) continue; if (r[0] === targetNick) pRecs.push({ date: r[1], agent: r[4] || '' }); }
    if (!pRecs.length) {
      return [{ json: { action: 'reply', to, message: targetNick + ' 目前還沒有交接紀錄，查不到代理人耶～可以提醒他填一下 🙏', rows: [] } }];
    }
    const pDm = userMessage.match(/(\d{1,2})[\/月](\d{1,2})/);
    if (pDm) { const q = singleDate(pDm[0]); const f = pRecs.filter(x => overlap(x.date, q, q)); if (f.length) pRecs = f; }
    const pWith = pRecs.filter(x => x.agent);
    if (!pWith.length) {
      return [{ json: { action: 'reply', to, message: targetNick + '（' + pRecs[0].date + '）還沒指定代理人喔～', rows: [] } }];
    }
    if (pWith.length === 1) {
      return [{ json: { action: 'reply', to, message: '👤 ' + targetNick + '（' + pWith[0].date + '）的代理人是 ' + pWith[0].agent, rows: [] } }];
    }
    return [{ json: { action: 'reply', to, message: '👤 ' + targetNick + ' 的代理人：\n' + pWith.map(x => '・' + x.date + '：' + x.agent).join('\n'), rows: [] } }];
  }

  const handoverIntent = /交接/.test(userMessage)
    || (targetNick && /(工作|負責|做什麼|在幹嘛|在忙|忙什麼|怎麼辦|事情|事項|處理|職務|代理)/.test(userMessage));
  if (handoverIntent) {
    if (!targetNick) {
      return [{ json: { action: 'reply', to, message: '要查誰的交接呢？請給「名字＋請假日期」，例如「小明 6/8 的交接」🙏', rows: [] } }];
    }
  let hand = [];
  for (let i = 1; i < handVals.length; i++) {
    const r = handVals[i]; if (!r[0]) continue;
    if (r[0] === targetNick) hand.push({ name: r[0], date: r[1], content: r[2], ts: r[3], agent: r[4] || '' });
  }
  if (!hand.length) {
    return [{ json: { action: 'reply', to, message: targetNick + ' 目前還沒填交接耶～可以提醒他補一下 🙏', rows: [] } }];
  }
  const dm = userMessage.match(/(\d{1,2})[\/月](\d{1,2})|今天|明天|後天/);
  let cand = hand;
  if (dm) { const q = singleDate(dm[0]); const f = hand.filter(h => overlap(h.date, q, q)); if (f.length) cand = f; }
  let target;
  if (cand.length === 1) target = cand[0];
  else {
    const dates = [...new Set(cand.map(h => h.date))];
    if (dates.length > 1) {
      return [{ json: { action: 'reply', to, message: targetNick + ' 有好幾段假，要查哪一段？\n' + dates.map(d => '・' + d).join('\n'), rows: [] } }];
    }
    cand.sort((a, b) => (a.ts < b.ts ? 1 : -1)); target = cand[0];
  }
  // 用「──── 更新 時間 ────」拆出每個版本：原始 + 後續更新
  const segs = String(target.content || '').split(/\n*──── 更新 (.+?) ────\n*/);
  const vers = [{ ts: '', body: stripHandoverHeader(segs[0] || '') }];
  for (let k = 1; k < segs.length; k += 2) {
    vers.push({ ts: (segs[k] || '').trim(), body: stripHandoverHeader(segs[k + 1] || '') });
  }
  const latest = vers[vers.length - 1];
  const latestTs = latest.ts || target.ts || '';
  let msg = '📋 ' + target.name + '（' + target.date + '）的交接';
  if (target.agent) msg += '\n👤 代理人：' + target.agent;
  if (latestTs) msg += '\n🕒 最新版：' + latestTs;
  msg += '\n\n' + latest.body;
  if (vers.length > 1) {
    msg += '\n\n— 📜 歷史紀錄 —';
    for (let k = vers.length - 2; k >= 0; k--) {
      msg += '\n\n【' + (vers[k].ts ? vers[k].ts : '原始版本') + '】\n' + vers[k].body;
    }
  }
  return [{ json: { action: 'reply', to, message: msg, rows: [] } }];
  }
}


let p;
try { p = JSON.parse(agentOut.match(/\{[\s\S]*\}/)[0]); }
catch (e) { return [{ json: { action: 'reply', to, message: '啊咧？我有點看不懂耶，可以換句話再說一次嗎～', rows: [] } }]; }

// 私訊寫入限制（測試期）：只有指定 userid 能在私訊請假/改/取消/外出；其餘導去群組
const PRIVATE_WRITE_ALLOWED = ['<LINE_USER_ID>4'];
if (sourceType === 'user' && ['register', 'cancel', 'modify', '外出'].includes(p.intent) && !PRIVATE_WRITE_ALLOWED.includes(ev.source.userId || '')) {
  return [{ json: { action: 'reply', to, message: '請假／修改／取消請到群組辦理哦～這樣大家都看得到、也比較不會漏 🙏', rows: [] } }];
}

// ===== 查詢 =====
if (p.intent === 'query') {
  const qd = (String(p.query_date || '') + ' ' + userMessage);
  let startD = null, endD = null, label = '', all = false;

  if (/全部|所有|全員|列出|整理|清單|歷史/.test(qd)
      && !/今天|今日|明天|明日|後天|本週|這週|下週|本月|這個月|\d/.test(qd)) {
    all = true; label = '全部請假紀錄';
  } else if (/本週|這週|這禮拜|本周|這周/.test(qd)) {
    startD = new Date(today); endD = new Date(today); endD.setDate(today.getDate() + ((7 - today.getDay()) % 7));
    label = '本週（' + fmt(startD) + '~' + fmt(endD) + '）';
  } else if (/下週|下周|下星期/.test(qd)) {
    const mon = new Date(today); mon.setDate(today.getDate() + ((8 - today.getDay()) % 7 || 7));
    const sun = new Date(mon); sun.setDate(mon.getDate() + 6);
    startD = mon; endD = sun; label = '下週（' + fmt(startD) + '~' + fmt(endD) + '）';
  } else if (/本月|這個月|這月/.test(qd)) {
    startD = new Date(today.getFullYear(), today.getMonth(), 1);
    endD = new Date(today.getFullYear(), today.getMonth() + 1, 0);
    label = '本月（' + fmt(startD) + '~' + fmt(endD) + '）';
  } else {
    const q = singleDate(p.query_date);
    startD = q; endD = q; label = fmt(q) + '(' + wd[q.getDay()] + ')';
  }

  let hit = leaves.filter(r => r.status !== 'cancelled' && (all || overlap(r.date, startD, endD)));
  hit.sort((a, b) => {
    const da = String(a.date).split('~')[0], db = String(b.date).split('~')[0];
    return da < db ? -1 : da > db ? 1 : 0;
  });

  let msg;
  if (!hit.length) {
    msg = pick(['津日 梅池道 查過囉～ 📋','報告！']) + '\n' + label + ' 沒有請假紀錄，大家都在崗位上 💪';
  } else {
    const lines = hit.map(r => {
      const tag = r.status === 'confirmed' ? '✅ 已確認' : '⏳ 待假單';
      return '・' + r.applicant + '（' + r.date + '｜' + r.category + '｜' + tag + '）';
    }).join('\n');
    msg = pick(['查到囉～ ✨','津日 梅池道 為你查好啦 📋','幫你整理好囉 📋']) + '\n' + label + '：\n' + lines;
  }
  return [{ json: { action: 'reply', to, message: msg, rows: [] } }];
}

// ===== 取消 / 修改 =====
if ((p.intent === 'cancel' || p.intent === 'modify') && Array.isArray(p.items) && p.items.length) {
  const it = p.items[0];
  const rawName = it.name ? String(it.name).trim() : '';
  // 名字要「真的出現在訊息原文」才採用（防 AI 從請假紀錄 JSON 腦補沒提到的人名）
  const _nameInMsg = rawName && userMessage.toLowerCase().includes(rawName.toLowerCase());
  let nick = null;
  if (_nameInMsg) {
    nick = findNick(rawName);
    if (!nick) return [{ json: { action: 'reply', to, message: '啊咧？找不到「' + rawName + '」這位同仁耶～', rows: [] } }];
  } else {
    // 沒有可信名字（沒打名字／用回覆改自己的假）→ 用發話者本人
    const senderId = ev.source.userId || '';
    const me = emps.find(e => e.uid && e.uid === senderId);
    if (me) nick = me.nick || me.real;
    else return [{ json: { action: 'reply', to, message: '要改誰的假呢？請打上名字（例：小明 改成事假），或先私訊我「綁定 暱稱」改自己的 🙏', rows: [] } }];
  }

  const endOf = d => { const s = String(d); return parseD(s.includes('~') ? s.split('~').pop() : s); };
  const tr = it.date ? resolveRange(it.date, null) : null;
  let hits = leaves.filter(r => {
    if (r.applicant !== nick || r.status === 'cancelled') return false;
    if (tr) return overlap(r.date, tr.start, tr.end);   // 有指定日期 → 照日期比對
    return endOf(r.date) >= today;                       // 沒指定 → 只考慮「還沒過期」的（過期的不可能是要改的）
  });

  if (hits.length === 0)
    return [{ json: { action: 'reply', to, message: '啊咧咧？找不到 ' + nick + ' 最近要' + (p.intent==='cancel'?'取消':'修改') + '的假耶，確認一下日期？', rows: [] } }];

  // 沒指定日期、又有多筆未過期 → 優先抓「還沒附假單截圖」的那筆（slip 空 = 還沒附證明，最可能是要動的）
  // 只縮到剛好一筆才自動處理；分不出來（都沒附 or 都附了）就往下問日期，不亂猜
  if (!tr && hits.length > 1) {
    const noSlip = hits.filter(h => !String(h.slip || '').trim());
    if (noSlip.length === 1) hits = noSlip;
  }
  // 仍多筆（有指定日期還對到多筆，罕見）→ 只問日期、不顯示假別（保護隱私）
  if (hits.length > 1) {
    const dates = [...new Set(hits.map(h => h.date))];
    return [{ json: { action: 'reply', to, message: nick + ' 那段有好幾筆，要' + (p.intent==='cancel'?'取消':'改') + '哪一天呢？（' + dates.join('、') + '）', rows: [] } }];
  }

  const rec = hits[0];
  if (p.intent === 'cancel') {
    const values = [rec.applicant, rec.date, rec.reason, rec.hours, 'cancelled', rec.category, rec.logtime, rec.lineid, rec.slip];
    return [{ json: { action: 'update', to, row: rec.row, values, message: '了解！✅ 已取消 ' + nick + ' 在 ' + rec.date + ' 的 ' + rec.category, rows: [] } }];
  }
  const nr = it.new_date ? resolveRange(it.new_date, it.hours ? Number(it.hours) : null) : null;
  const newDate = nr ? nr.dateStr : rec.date;
  // 相對時數：回診人多「+1小」「多2小時」「再加1小」「少1小時」→ 用原時數加減；否則照舊(設定)
  let newHours;
  const _relAdd = userMessage.match(/(?:[+＋]|加|多|再加?)\s*(\d+(?:\.\d+)?)\s*(?:小時|小|時|h)/i);
  const _relSub = userMessage.match(/(?:[-－]|減|少)\s*(\d+(?:\.\d+)?)\s*(?:小時|小|時|h)/i);
  if (_relAdd || _relSub) {
    const _base = parseFloat(rec.hours) || 0;
    const _delta = _relAdd ? parseFloat(_relAdd[1]) : -parseFloat(_relSub[1]);
    newHours = String(Math.max(0, _base + _delta));
  } else {
    newHours = it.hours ? String(it.hours) : (nr ? String(nr.hours) : rec.hours);
  }
  const newCat = it.category || rec.category;
  const newReason = it.reason || rec.reason;
  const values = [rec.applicant, newDate, newReason, newHours, rec.status, newCat, rec.logtime, rec.lineid, rec.slip];
  return [{ json: { action: 'update', to, row: rec.row, values, message: '了解！✅ ' + nick + ' 的請假已更新\n日期：' + newDate + '｜假別：' + newCat + '｜' + hLabel(newHours), rows: [] } }];
}

// ===== 外出 / 公出 =====
if (p.intent === '外出' && Array.isArray(p.items) && p.items.length) {
  const todayStr = fmt(today);
  const rows = [], ok = [], nf = [];
  for (const it of p.items) {
    const nick = findNick(it.name);
    if (!nick) { nf.push(it.name); continue; }
    const reason = it.reason || '外出';
    rows.push([nick, todayStr, reason, '0', 'confirmed', '外出', nowStr, to, '']);
    ok.push({ nick, reason });
  }
  const parts = [];
  for (const o of ok) parts.push('📮 ' + o.nick + ' 外出：' + o.reason);
  for (const n of nf) parts.push('❓ 找不到「' + n + '」這位同仁');
  const head = ok.length ? '收到～幫你記一下外出（在勤、不扣假）✅' : '';
  const msg = (head ? head + '\n' : '') + parts.join('\n');
  return [{ json: { action: rows.length ? 'append' : 'reply', to, message: msg, rows } }];
}

// ===== 登記 =====
if (p.intent === 'register' && Array.isArray(p.items)) {
  const rows = [], ok = [], dup = [], nf = [], vague = [], slipnote = [];
  for (const it of p.items) {
    const nick = findNick(it.name);
    if (!nick) { nf.push(it.name); continue; }
    if (isVague(it.date)) { vague.push(nick); continue; }
    if (!it.category && /補.{0,4}假單|假單.{0,4}(送出|傳|補|上傳|提交|補上|已傳|已送)|補件|補單/.test(userMessage)) { slipnote.push(nick); continue; }
    const rr = resolveRange(it.date, it.hours ? Number(it.hours) : null);
    const cat = it.category || '其他';
    // 只有「同人+日期重疊+同假別+時數相加>8」才算重複（允許同日不同假別、或同日兩個半天）
    const exists = leaves.find(r => r.applicant === nick && r.status !== 'cancelled' && overlap(r.date, rr.start, rr.end) && ((parseFloat(r.hours) || 0) + (parseFloat(rr.hours) || 0) > 8));
    if (exists) { dup.push({ nick, date: exists.date, category: exists.category, status: exists.status }); continue; }
    const holidayDates = [];
    { const d = new Date(rr.start); while (d <= rr.end) { if (isHoliday(d)) holidayDates.push(fmt(d) + '(' + wd[d.getDay()] + ')'); d.setDate(d.getDate() + 1); } }
    rows.push([nick, rr.dateStr, it.reason || cat, String(rr.hours), 'pending', cat, nowStr, to, '']);
    ok.push({ nick, date: rr.dateStr, category: cat, hours: rr.hours, holidayDates });
  }
  const parts = [];
  for (const o of ok) {
    parts.push('✅ ' + o.nick + '\n日期：' + o.date + '｜假別：' + o.category + '｜' + hLabel(o.hours));
    if (o.holidayDates.length) parts.push('⚠️ 提醒：' + o.holidayDates.join('、') + ' 為國定假日（公休），確認是否真的需要請這天的假？');
  }
  for (const d of dup) parts.push('⚠️ ' + d.nick + ' 這個假期已登記過囉（' + d.date + '｜' + d.category + '｜' + (d.status==='confirmed'?'已確認':'待假單') + '）');
  for (const n of nf) parts.push('❓ 找不到「' + n + '」這位同仁，請確認名字');
  for (const v of vague) parts.push('⏰ ' + v + ' 要請「哪一天」呢？給我日期就好（例：7/1 或 下週二）🙏');
  for (const s of slipnote) parts.push('📋 ' + s + ' 的假單我收到「圖片」就會自動處理哦～若要用文字補登請假，請給「日期＋假別」（例：' + s + ' 昨天 病假）🙏');
  const head = ok.length ? pick(['津日 梅池道報告～ ✅','津日 梅池道 幫你記好囉 ✅','收到收到～ ✅']) : '';
  const tail = ok.length ? '\n假單記得要傳哦 🙏' : '';
  const msg = (head ? head + '\n' : '') + parts.join('\n') + tail;
  return [{ json: { action: rows.length ? 'append' : 'reply', to, message: msg, rows, registered: ok } }];
}

// ===== 其他：閒聊 / 不相關 =====
if (sourceType !== 'user' && !mentioned) {
  return [];
}

// === SOP 行為式延續：私訊、在 SOP 視窗內、非純打招呼 → 當 SOP 追問（不用再打 /sop）。
//     放在所有明確功能(綁定/交接/查交接/請假/修改取消)之後 → 做別的事一律優先、自動退出 SOP ===
if (sourceType === 'user' && wasInSop) {
  const _greet = /^[\s。.，,！!？?~～、]*(謝謝|感謝|3q|thx|thanks?|thank you|不客氣|好的?|好喔|好哦|好啊|好呀|了解|收到|ok|okay|讚|棒|辛苦了?|嗨+|哈囉|hi|hello|哈+|早安?|午安|晚安|掰+|bye|拜拜|愛你|沒事|沒了|結束)[你妳您我們大家啦囉喔哦呀耶了嗎呢～~。.!！?？,，、\s👍🙏😊❤️]*$/i;
  if (userMessage.trim() && !_greet.test(userMessage.trim())) {
    let sopAns = '抱歉，SOP 助理暫時無法回應，請稍後再試。';
    try {
      const r2 = await this.helpers.httpRequest({
        method: 'POST', url: 'http://localhost:3345/ask',
        headers: { 'Content-Type': 'application/json' },
        body: { sessionId: ev.source.userId, message: userMessage.trim(), client: 'line', followup: true },
        json: true
      });
      if (r2 && r2.answer) sopAns = r2.answer;
    } catch (e) {}
    sopArm();
    return [{ json: { action: 'reply', to, message: sopAns + '\n\n（還在問 SOP，要做別的直接說就好）', rows: [] } }];
  }
