}
function parseJson(raw, fallback) {
  try { const m = raw.match(/[\{\[][\s\S]*[\}\]]/); if (m) return JSON.parse(m[0]); } catch (e) {}
  return fallback;
}
const pad = n => String(n).padStart(2, '0');
