function contentDump(d) {
  let t = '標題：' + (d.title||'') + '\n總結：' + (d.summary||'') + '\n適用對象：' + (d.who||'') +
          '\n適用情境：' + (d.when||'') + '\n前置：' + [d.pre_sys,d.pre_tool,d.pre_doc].filter(Boolean).join('；') + '\n步驟：\n';
  (d.steps||[]).forEach((s,i)=>{ t += (i+1)+'. '+(s.title||'')+'｜執行人:'+(s.who||'-')+'｜位置:'+(s.where||'-')+
        '｜動作:'+(s.do||'-')+'｜完成:'+(s.done||'-')+'｜注意:'+(s.note||'-')+'\n'; });
  t += '異常處理：' + (d.exc||'') + '\n';
  if (d.answers && d.answers.length) t += '使用者補充回答：' + JSON.stringify(d.answers) + '\n';
  return t;
}
function faqText(faqs){
  if (!faqs || !faqs.length) return '（無）';
  return faqs.map(f => '**Q：' + (f.q||'') + '**\nA：' + (f.a||'') + '\n').join('\n');
}
function buildMd(d, faq) {
  let m = '---\nnamespace: ' + (d.dept||'未分類') + '\ndoc_type: SOP\nversion: "' + todayStr + '"\nowner: "' + (d.owner||'') + '"\n---\n\n';
  m += '# ' + (d.title||'') + '\n> **重要程度**：' + (d.level||'一般') + '\n\n## 一句話核心總結\n' + (d.summary||'') + '\n\n---\n\n';
  m += '## 適用對象\n| 項目 | 詳細描述 |\n|------|---------|\n| 適用對象 | ' + (d.who||'（未填）') + ' |\n| 適用情境 | ' + (d.when||'（未填）') + ' |\n\n---\n\n';
  const pre = [];
  if (d.pre_sys) pre.push('- **系統權限**：' + d.pre_sys);
  if (d.pre_tool) pre.push('- **硬體/工具**：' + d.pre_tool);
  if (d.pre_doc) pre.push('- **必要資料**：' + d.pre_doc);
  m += '## 前置準備\n' + (pre.length ? pre.join('\n') : '（無特殊前置需求）') + '\n\n---\n\n## 標準步驟\n';
  (d.steps||[]).forEach((s,i)=>{
    m += '### 步驟 ' + (i+1) + '：' + (s.title||'') + '\n';
    if (s.who) m += '- **執行人**：' + s.who + '\n';
    if (s.where) m += '- **操作位置**：' + s.where + '\n';
    if (s.do) m += '- **具體動作**：' + s.do + '\n';
    if (s.done) m += '- **完成指標**：' + s.done + '\n';
    if (s.note) m += '- **注意事項**：' + s.note + '\n';
    m += '\n';
  });
  m += '---\n\n## 異常處理\n' + (d.exc||'（暫無已知異常狀況）') + '\n\n---\n\n## 常見問題 FAQ\n' + faq + '\n\n---\n\n## 維護資訊\n- **最後更新**：' + todayStr + '\n- **文件負責人**：' + (d.owner||'') + '\n';
  return m;
