const rank = s => ({confirmed:3, pending:2, awaiting:1})[s] || 0;

const header = (vals[0] || []).slice();
// 資料列正規化成 9 欄（A:I），保留原順序、原內容；保留空白列佔位（維持列數對齊）
const data = vals.slice(1).map(r => { const x=(r||[]).slice(); while(x.length<9)x.push(''); return x; });

// 只挑「有名字」的列來比對重複；空白佔位列不參與，但仍保留在輸出裡
const idx = data.map((r,i)=>({i,r})).filter(x=>String(x.r[0]||'').trim());

const used = new Set();
let removed = 0;
for (let a=0; a<idx.length; a++){
  if (used.has(idx[a].i)) continue;
  for (let b=a+1; b<idx.length; b++){
    if (used.has(idx[b].i)) continue;
    const A=idx[a].r, B=idx[b].r;
    if (A[4]==='cancelled' || B[4]==='cancelled') continue;
    if (String(A[0]) !== String(B[0])) continue;          // 同一個人
    if ((parseFloat(A[3])||0) + (parseFloat(B[3])||0) <= 8) continue;   // 同日重疊、時數相加≤8h → 視為不同時段(上午+下午)兩筆都留；不靠假別(特休/遞延特休名稱可能不同)
    if (!overlap(range(A[1]), range(B[1]))) continue;      // 日期重疊
    const drop = rank(A[4]) >= rank(B[4]) ? idx[b].i : idx[a].i;   // 留分數高的，丟另一個
    used.add(drop);
    data[drop][4] = 'cancelled';
    data[drop][2] = (data[drop][2] || '') + '（系統自動合併重複）';
    removed++;
    if (drop === idx[a].i) break;   // a 被丟了 → 跳出內層
  }
}

if (removed === 0) return [];        // 沒有重複 → 不寫，避免無謂整段覆寫
const out = [header, ...data];
return [{ json: { values: out, endRow: out.length, removed } }];

const registered = ($('大腦').first().json.registered) || [];
if (!registered.length) return [{ json: { skip: true } }];
const empVals = ($('讀取員工').first().json.values) || [];
const idMap = {};
for (let i = 1; i < empVals.length; i++) { const r = empVals[i]; if (r[1]) idMap[r[1]] = r[2]; }
const TOKEN = '<LINE_CHANNEL_ACCESS_TOKEN>';
for (const o of registered) {
  const uid = idMap[o.nick];
  if (!uid) continue;
  const tpl = ('📋 請假交接單（請完整複製整段文字、填好後回傳，標題別刪哦）\n\n姓名：{NICK}\n請假期間：{DATE}\n代理人：\n----------------------\n📝 交接工作：\n⚠️ 注意事項：\n✏️ 其他（可自訂內容）：').replace('{NICK}', o.nick).replace('{DATE}', o.date);
  try {
    await this.helpers.httpRequest({ method: 'POST', url: 'https://api.line.me/v2/bot/message/push',
      headers: { 'Authorization': `Bearer ${TOKEN}`, 'Content-Type': 'application/json' },
      body: { to: uid, messages: [{ type: 'text', text: tpl }] } });
  } catch (e) {}
}
return [{ json: { sent: true } }];

const ops = ($('解析假單結果').all() || []).map(x => x.json).filter(o => o && o.action === 'add' && Array.isArray(o.values));
if (!ops.length) return [{ json: { skip: true } }];
const empVals = ($('讀取員工2').first().json.values) || [];
const idMap = {};
for (let i = 1; i < empVals.length; i++) { const r = empVals[i]; if (r[1]) idMap[r[1]] = r[2]; }
const TOKEN = '<LINE_CHANNEL_ACCESS_TOKEN>';
for (const o of ops) {
  const nick = o.values[0], date = o.values[1];
  const uid = idMap[nick];
  if (!uid) continue;
  const tpl = ('📋 請假交接單（請完整複製整段文字、填好後回傳，標題別刪哦）\n\n姓名：{NICK}\n請假期間：{DATE}\n代理人：\n----------------------\n📝 交接工作：\n⚠️ 注意事項：\n✏️ 其他（可自訂內容）：').replace('{NICK}', nick).replace('{DATE}', date);
  try {
    await this.helpers.httpRequest({ method: 'POST', url: 'https://api.line.me/v2/bot/message/push',
      headers: { 'Authorization': `Bearer ${TOKEN}`, 'Content-Type': 'application/json' },
      body: { to: uid, messages: [{ type: 'text', text: tpl }] } });
  } catch (e) {}
}
return [{ json: { sent: true } }];
